body {
    margin: 0;
    font-family: Arial, Helvetica, sans-serif;
    background: #f5f5f5;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
}

.chat-wrapper {
    width: 100%;
    max-width: 600px;
    height: 90vh;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    overflow: hidden;
}

.chat-list {
    flex: 1;
    list-style: none;
    margin: 0;
    padding: 1rem;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.chat-list li {
    max-width: 70%;
    padding: 0.6rem 1rem;
    border-radius: 12px;
    line-height: 1.4;
}

.chat-list .user {
    align-self: flex-end;
    background: #007bff;
    color: #fff;
}

.chat-list .assistant {
    align-self: flex-start;
    background: #e2e2e2;
    color: #000;
}

.input-area {
    display: flex;
    padding: 0.5rem;
    border-top: 1px solid #ddd;
    background: #fafafa;
}

#prompt {
    flex: 1;
    resize: none;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
}

#send {
    margin-left: 0.5rem;
    padding: 0 1rem;
    font-size: 1rem;
    background: #28a745;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

#send:hover { background: #218838; }

document.addEventListener('DOMContentLoaded', () => {
  const promptEl = document.getElementById('prompt');
  const sendBtn = document.getElementById('send');
  const chatList = document.getElementById('chat');

  const addMessage = (text, cls) => {
    const li = document.createElement('li');
    li.className = cls;
    li.textContent = text;
    chatList.appendChild(li);
    chatList.scrollTop = chatList.scrollHeight;
    return li;
  };

  const sendMessage = async () => {
    const prompt = promptEl.value.trim();
    if (!prompt) return;
    promptEl.value = '';
    addMessage(prompt, 'user');

    // Placeholder for assistant response
    const assistantLi = addMessage('', 'assistant');

    // Build URL with query param because EventSource only supports GET
    const url = `/chat?prompt=${encodeURIComponent(prompt)}`;
    const source = new EventSource(url);

    source.addEventListener('message', (e) => {
      assistantLi.textContent += e.data;
      chatList.scrollTop = chatList.scrollHeight;
    });

    source.addEventListener('error', (e) => {
      assistantLi.textContent = 'Error: connection lost';
      assistantLi.style.background = '#ffcccc';
      source.close();
    });
  };

  sendBtn.addEventListener('click', sendMessage);
  promptEl.addEventListener('keypress', (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  });
});

